def measure_forecast_accuracy(
    forecast: list[dict],    # [{"month": "...", "point_usd": ...}, ...]
    actuals: list[dict],     # [{"month": "...", "cost_usd": ...}, ...]
) -> dict:
    """
    Compute Mean Absolute Percentage Error (MAPE) and bias for a set of forecasts.
    MAPE < 10%: excellent. 10-20%: acceptable. > 20%: recalibrate the model.
    """
    actual_map = {r["month"]: r["cost_usd"] for r in actuals}
    errors = []
    for f in forecast:
        actual = actual_map.get(f["month"])
        if actual is None or actual == 0:
            continue
        error_pct = (f["point_usd"] - actual) / actual * 100
        errors.append({"month": f["month"], "error_pct": error_pct,
                        "abs_error_pct": abs(error_pct)})

    if not errors:
        return {"mape": None, "bias_pct": None, "n": 0}

    mape = sum(e["abs_error_pct"] for e in errors) / len(errors)
    bias = sum(e["error_pct"] for e in errors) / len(errors)
    return {
        "mape": round(mape, 1),
        "bias_pct": round(bias, 1),   # positive = over-forecasted; negative = under-forecasted
        "n": len(errors),
        "assessment": (
            "excellent" if mape < 10
            else "acceptable" if mape < 20
            else "recalibrate_required"
        ),
    }
